INSERT INTO productos
  (id, nombre, precio, imagen, descripcion, medidas, material, categoria_id, subcategoria)
VALUES
  (1, 'CAMA DINTEL', 3680000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885739/CAMA_DINTEL_xxcgsr.jpg', 'Elegancia y sofisticación se unen en esta Cama Dintel. Su diseño exclusivo de cabecera tipo arco aporta un toque arquitectónico único a tu dormitorio. Fabricada en finos madera de Flor Morado, una especie nativa colombiana reconocida por su durabilidad excepcional y vetas naturales que la convierten en una pieza de arte. El acabado perfecto combina tradición artesanal con diseño contemporáneo para crear el ambiente de descanso que mereces.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (2, 'CAMA LINEAL', 2880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885735/CAMA_LINEAL_qmt8po.jpg', 'La Cama Lineal representa la esencia del minimalismo elegante. Su diseño de líneas limpias y tapizado impecable se integra perfectamente en cualquier espacio moderno. Los apliques horizontales o verticales permiten personalización según tu estilo, creando una pieza única que refleja tu personalidad. El tejido de alta calidad asegura comodidad duradera mientras su estructura robusta garantiza años de descanso tranquilo.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada - Apliques Horizontal/Vertical (según solicitud del cliente)', 1, 'camas'),
  (3, 'CAMA BALI', 2880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776890931/CAMA_BALI.jpg_us5rhr.jpg', 'Inspírate en los sabores tropicales con la Cama Bali, una pieza que trae la serenidad de las islas a tu hogar. Su diseño exclusivo de cabecera con courved orgánicas crea un ambiente relajante y acogedor, perfecto para escapar del estrés diario. El tapizado premium ofrece la combinación ideal de comfort y estilo, transformando tu habitación en un santuario de paz.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada', 1, 'camas'),
  (4, 'CAMA FIGY (Con Alerones)', 5780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885741/CAMA_FIGY_CON_ALERONES_uriiot.jpg', 'La Cama Figy con Alerones es la pieza central definitiva para tu dormitorio master. Su diseño spectacular de cabecera con alerones flanking crea un impacto visual dramático que establece el tono de todo el espacio. Fabricada en prestigiosa madera Flor Morado, cada pieza exhibe vetas únicas que la hacen irrepetible. Los alerones proporciona soporte adicional para leer o ver televisión,融合ando funcionalidad con diseño de autor.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (5, 'CAMA APLIQUES CENTRAL', 2680000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884282/CAMA_APLIQUES_CENTRAL_btou2m.jpg', 'Distínguete con la Cama Apliques Central, donde el diseño encuentra la artesanía. Los appliques centrada en la cabecera crean un focal point elegante que captura la atención inmediatamente. En constructores con prestigiosa madera Flor Morado, esta cama combina la calidez natural de la madera con detalles decorativos sofisticados, resultando en una pieza que trasciende lo ordinario.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (6, 'CAMA CHOCOLATINA', 1580000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884797/CAMA_CHOCOLATINA_zhgeta.jpg', 'La Cama Chocolatina bringe calidez y accesibilidad a tu espacio de descanso. Su diseño clásico de cabecera con acabado en Triple Cedro Pintado ofrece durabilidad comprobada a un precio excepcional. Esta opción perfecta para quienes buscan calidad sin comprometer el presupuesto, sin sacrificar estilo. El acabado paint de primera garantizan una apariencia impecable por años.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Triple Cedro Pintada', 1, 'camas'),
  (7, 'CAMA MACANA', 3780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885732/CAMA_MACANA_ewjlro.jpg', 'La Cama Macana es una declaración de buen gusto. Su diseño robusto de cabecera en madera Flor Morado exhibe la belleza natural de esta especie premium, con vetas que crean patrones visuales únicos en cada pieza. La construcción sólida asegura estabilidad duradera mientras el diseño atemporal se adapta a múltiples estilos decorativos, desde clásico hasta contemporáneo.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (8, 'CAMA ESTOCOLMO', 3780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885732/CAMA_ESTOCOLMO_gkxg9b.jpg', 'Descubre el diseño escandinavo con la Cama Estocolmo. Este modelo trae la esencia del mobiliario nórdico a tu dormitorio, combinando simplicidad funcional con materiales naturales. La cabecera de diseño limpio en pino de calidad ofrece líneas depuradas que maximizan la sensación de espacio, perfecta para квартиры modernas.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Pino', 1, 'camas'),
  (9, 'CAMA SAVANNA', 3380000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776886134/CAMA_SAVANNA_udkmbt.jpg', 'La Cama Savanna transforma tu dormitorio en un refugio de elegancia colonial. Su tapizado lineal vertical crea textura y profundidad que captura la luz de manera espectaculary única. El diseño inspirado en classic mobilier estadounidense combina comfort contemporáneo con atemporalidad stylística, resultando en una pieza que mejora con el tiempo.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada Lineal Vertical', 1, 'camas'),
  (10, 'CAMA DIAMANTE', 3680000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884795/CAMA_DIAMANTE_n66kka.jpg', 'Brilla con la Cama Diamante, una pieza que captura la luz y la reflexión en cada ángulo. Su diseño geométrico de facets crea movement visual dinámico que añade vida a tu espacio. La combinación de lamina de Flor Morado natural con el corte diamante produce un efecto tridimensional único, haciendo de cada noche una experiencia visual tão atractiva como el comfort físico.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Flor Morado Natural Lamina', 1, 'camas'),
  (11, 'CAMA BARCELONETA', 2880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884797/CAMA_BARCELONETA_ggvb6e.jpg', 'Lleva el encanto Mediterráneo a tu hogar con la Cama Barceloneta. Su diseño relajado y sofisticado evoca las costas españolas, creando una atmósfera vacacional permanente en tu dormitorio. La cabecera de laminado en Flor Morado natural combina calidez con durabilidad, mientras las líneas suaves invitan al descanso. Es la opción perfecta para quienes buscan un escape sin salir de casa.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Flor Morado Natural Lamina', 1, 'camas'),
  (12, 'CAMA VIENNA', 2980000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776886132/CAMA_VIENNA_hcs8ez.jpg', 'Experimenta la tradición Viennera con un giro contemporáneo. La Cama Vienna presenta su tapizado de diseño a cuadros que aporta carácter y personalidad a tu espacio. Este patrón clásico actualizado crea un ambiente acogedor sin sacrificar modernidad, haciendo juego perfecto con múltiples paletas de color y estilos decorativos.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada Cuadros', 1, 'camas'),
  (13, 'CAMA OSLO', 2680000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885728/CAMA_OSLO_ah0ksd.jpg', 'La Cama Oslo trae la esencia del diseño nórdico a tu espacio. Su cabecera de laminado en Flor Morado natural presenta líneas minimalistas que maximizan la sensación de espacio y luz. Esta pieza funcional y hermosa representa la filosofía escandinava de que menos es más, creando un environnement tranquilo ideal para el descanso.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Flor Morado Natural Lamina', 1, 'camas'),
  (14, 'CAMA ÉBANO', 2880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885737/CAMA_EBANO_pnjwbd.jpg', 'La Cama Ébano es elegancia dark en su forma más pura. El intenso color de la madera Flor Morado crea un statement audaz que domina el espacio con sofisticación. Esta pieza atemporal irradia lujo contenido, perfecta para crear un dormitorio con carácter fuerte y personalidad definidos. La madera de primera calidad asegura belleza duradera.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (15, 'CAMA BETHEL', 3380000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884792/CAMA_BETHEL_uxzsbw.jpg', 'La Cama Bethel combina comodidad con estilo en perfectaHarmonía. Su cabecera tapizada oferece un respaldo perfecto para leer o ver television, mientras el diseño líneas aporta presencia visual sin abrumar el espacio. El tapizado de calidad premium garantiza comfort duradero y facilidad de mantenimiento, convirtiendo tu cama en el centro de tu régimen de autocuidado.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada', 1, 'camas'),
  (16, 'CAMA EDEN', 3380000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885736/CAMA_EDEN_tps6fb.jpg', 'Tu dormitorio merece ser un edén moderno. La Cama Eden ofrece el sanctuary perfecto con su diseño tapizado que combina softness con soporte. La поверхность suavemente texturizada Invita al descanso, mientras las líneasclean permiten múltiples posibilidades de styling. Es el refugio definitivo para recuperar energía después de días largos.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada', 1, 'camas'),
  (17, 'CAMA SIENNA', 3380000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776886131/CMA_SIENNA_cxy6gr.jpg', 'La Cama Sienna trae calidez terrenal a tu space. Su diseño tapizado de perfil bajo crea un profile sleek que hace tu habitación parecer más espaciosa, mientras ofrece comfort excepcional. Esta pieza versátil trabaja igual de bien en minimalist spaces como en maximalist enviros, adaptándose a tu estilo de vida.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada', 1, 'camas'),
  (18, 'CAMA SIENNA DIVIDIDA (Cama Baul)', 3380000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776886135/CAMA_SIENNA_DIVIDIDA_nt8lhu.jpg', 'Maximiza tu espacio con la Cama Sienna Dividida, el diseño innovador que combina descanso con almacenaje. Esta cama baul ofrece storage generoso sin sacrificar estilo, manteniendo el look elegante de la Sienna original mientras addiciona funcionalidad práctica. Perfect para viviendas donde cada metro cuadrado cuenta.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada', 1, 'camas'),
  (19, 'CAMA VERTICE', 2980000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776886133/CAMA_VERTICE_fslu9n.jpg', '数学 Meets Design con la Cama Vértice. Su diseño de cabecerageometric crea un punto focal dinámico que captura atenção desde cualquier ángulo. La precisión del corte en madera Flor Morado demuestra elskill artesanal, mientras el resultado final aporta un toque de arquitectura a tu dormitorio. Ideal para quienes aprecian la innovación.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (20, 'CAMA MIAMI', 2680000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885732/CAMA_MIAMI_ktnbrd.jpg', 'Vive el lifestyle playero con la Cama Miami. Su combinación de madera Flor Morado con chapilla crea un look sofisticado que evoca la elegancia costera. El diseño clean pero con carácter aporta freshness a tu dormitorio, haciendo cada día sienta como unas mini vacaciones. Es la opción perfecta para квартиры con espíritu relajado.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado y Chapilla', 1, 'camas'),
  (21, 'CAMA ALISTONADA', 2880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884287/CAMA_ALISTONADA_desue2.jpg', 'Añade текстура y dimensión con la Cama Alistonada. Su diseño de listones proporciona interés visual que captura la luz de manera única, creando sombras y reflejos que dynamizan el espacio. La qualidade de la madera Flor Morado asegura que esta pieza sea un heirloom que puedes passar de generación en generación.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (22, 'CAMA MACARENA', 2980000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776885736/CAMA_MACARENA_pc2zuy.jpg', 'La Cama Macarena es tradición con corazón. Su diseño de cabecera con postesy cabeceros bercerita la historia del mobiliario clásico mientras mantiene funcionalidad moderna. La madera Flor Morado de primera calidad añade calidez natural al espacio, creando un ambiente acogedor que welcome you home después de un largo día.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (23, 'CAMA FLOR MORADO LISA', 2980000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776878013/flor_morado_lisa.jpg_1_ttf9cq.jpg', 'La simplicidadexquisita encuentra en la Cama Flor Morado Lisa. Su diseño minimalista deja que la beautifulz natural de la madera seja la estrella del show. Las vetas únicas de cada pieza crean arte orgánico que no puede ser reproducido, haciendo tu cama verdaderamente única. Es la elección perfecta para quienes aprecian la belleza natural.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Madera Flor Morado', 1, 'camas'),
  (24, 'BASE CAMA', 980000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776884306/BASE_CAMA_bhhyrn.jpg', 'La Base Cama es funcionalidad puro en su forma más elegante. Su diseño tapizado ofreceun foundation sólida para tu colchón mientras mantiene un look sofisticado. Esta base también puede funcionar como solución de storage, proporcionando espacio adicional para sábanas, mantas u otrositems sin sacrificar estética. Calidad que ves y sientes.', 'Puede ajustarse/fabricarse según gusto y necesidad del cliente', 'Tapizada', 1, 'camas'),
  (25, 'MESA NOCHE BELMONTE', 780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887119/MESA_BELMONTE_emvbhx.jpg', 'La Mesa Noche Belmonte aporta distinción a tu espacio de descanso. Su diseño elegante en Flor Morado natural crea el complemento perfecto para cualquier cama, añadiendo funcionalidad sin sacrificar estilo. El tamaño optimizado cabe perfectamente junto a cualquier cama mientras ofrece storage suficiente para tus essentials nocturnos.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (26, 'MESA NOCHE MIAMI UN CAJON', 780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887036/MESA_MIAMI_jdfmkx.jpg', 'Funcionalidad meetstyle en la Mesa Noche Miami. Su cajón único proporciona storage organizado para objetos personales, mientras su diseño sleek en Flor Morado natural añade calidez al dormitorio. El tamaño compacto es perfecto para espacios reducidos sin comprometer accesibilidad. Tu mesita de noche ideal espera.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (27, 'MESA NOCHE TV DUPLEX', 780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887023/MESA_TV_DUPLEX_flwwmy.jpg', 'La Mesa Noche TV Duplex trae innovación a tu bedroom. Su diseño de dos niveles ofrece múltiples posibilidades: un nivel para tu lamparita, otro para el control remoto y otros essentials. La combinación de Cedro con Flor Morado natural añade variación textural mientras mantiene sofisticación.', '0.50 x 0.40 aprox', 'Cedro, Flor Morado Natural', 1, 'mesas_noche'),
  (28, 'MESA NOCHE PIRAMIDE', 780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887033/MESA_PIRAMIDE_nskqf5.jpg', 'Geometría meets functionality con la Mesa Noche Pirámide. Su diseño pyramidal único llama la atención mientras ofrece storage prático. El acabado en Flor Morado natural deja apreciar la belleza de la madera, convirtiendo un mueble utilitario en arte funcional para tu habitación.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (29, 'MESA NOCHE MARGARITA', 780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887038/MESA_MARGARITA_kvarad.jpg', 'La Mesa Noche Margarita trae delicadeza floral a tu dormitorio. Su diseño exclusivo parece una flor aberta, creando un punto focal encantador. Disponible en versión pintada o natural, puedes elegir quella que mejor complemente tu decoración. Es la mesita perfecta para quienes aprecian detalles únicos.', '0.50 x 0.40 aprox', 'Flor Morado Natural (Pintado: $780.000 / Flor Morado: $880.000)', 1, 'mesas_noche'),
  (30, 'MESA NOCHE DIAMANTE', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887038/MESA_DIAMANTE_dmz4ml.jpg', 'Brilla con la Mesa Noche Diamante. Su diseño geométrico unique captura luz de maneras herramient creating sombras fascinantes. El Flor Morado natural asegura durabilidad excepcional mientras el diseño diamond crea movimiento visual que animates tu espacio.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (31, 'MESA NOCHE MACANA', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887035/MESA_MACANA_y0ri5c.jpg', ' strength and style se unen en la Mesa Noche Macana. Su diseño robusto de líneas definidas aporta presencia sin abrumar el espacio. El Flor Morado natural de primera calidad garantiza que esta pieza durará generaciones, convirtiéndose en heredanza familiar.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (32, 'MESA NOCHE SANTA MARTA', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887034/MESA_SANTA_MARTA_qnidpr.jpg', 'Vive el encanto caribe con la Mesa Noche Santa Marta. Su diseño exclusivo en lamina Flor Morado aporta carácter playero a tu espacio. Esta pieza crea el equilibrio perfecto entre funcionalidad y estilo costeño, haciendo tu nórdico suite feel como unas vacaciones permanentes.', '0.50 x 0.40 aprox', 'Lamina Flor Morado', 1, 'mesas_noche'),
  (33, 'MESA NOCHE TV UN CAJON', 780000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887032/MESA_TV_1_CAJON_b34wql.jpg', 'La Mesa Noche TV Un Cajón es el companion perfecto para lazy Sundays. Su cajón espacioso guarda todo lo que necesitas a la mano mientras su diseño clean no compite con tu television o decoración. El Flor Morado natural añade calidez, haciendo de tu rincón de entretenimiento algo aún más demócr.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (34, 'MESA NOCHE DELTA', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887120/MESA_DELTA_men0dx.jpg', 'La letra Delta gets un makeover con la Mesa Noche Delta. Su diseño de forma triangular unique crea interest visual dinámico. Esta pieza es el conversation starter perfecto que además proporciona storage práctico para tus esenciales nocturnos. Innovación que ves y usas quotidianamente.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (35, 'MESA DE NOCHE AMIGABLE', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887120/MESA_AMIGABLE_nxh0wb.jpg', 'La Mesa Amigable realmente live up to su nombre. Su diseño accesible y functional hace que reach para tu glass de agua o libro sea natural. El storage organizado mantiene todo a mano sin clutter, mientras su presencia amable aporta calidez a tu sanctuary nocturno.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (36, 'MESA NOCHE BARCELONETA', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887117/MESA_BARCELONETA_gappzh.jpg', 'El Mediterranean vibe llega a tu bedside con la Barceloneta. Este diseño brings the relaxed elegance de las costas españolas a tu hogar. Su appeal atemporal funciona perfectamente con múltiples estilos decorativos, desde clásico hasta contemporáneo.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (37, 'MESA NOCHE DEKO', 880000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887117/MESA_DEKO_c03uta.jpg', 'Diseño que declara: Deko. Esta mesa noche combina funcionalidad con statement de estilo. Su Silhouette distintivo aporta personalidad a tu espacio mientras mantiene toda la utility que necesitas. Es la pieza que tu bedroom ha estado esperando.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (38, 'MESA DE NOCHE ESTOCOLMO', 980000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887038/MESA_ESTOCOLMO_zb7dqf.jpg', 'La excelencia nórdica se manifiesta en la Mesa Noche Estocolmo. Su diseño escandinavo clean y funcional exemplifica el philosophy de que menos es más. El Flor Morado natural mantiene calidez mientras el diseño minimalista maximiza la sensación de espacio. Funcionalidad en su expresión más pura.', '0.50 x 0.40 aprox', 'Flor Morado Natural', 1, 'mesas_noche'),
  (39, 'COLCHON SOPHIA', 760000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887518/COLCHON_SOPHIA_ixhjbr.jpg', 'El.Colchón Sophia representa la combinación perfecta de comfort y accesibilidad. Su construcción standard ofrece el soporte equilibrado que necesitas para noches de sueño reparador. La densidad apropiada se adapta a tu cuerpo, proporcionando el soporte spinal correcto mientras mantiene confort suave. Es el choice ideal para quienes buscan calidad sin complicación.', '1.00 x 1.80 / 1.00 x 1.90 / 1.20 x 1.90 / 1.40 x 1.90', 'Standard', 1, 'colchones'),
  (40, 'COLCHON MONTECARLO', 1490000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887519/COLCHON_MONTECARLO_xyxrtn.jpg', 'Vive la vida de lujo con el Colchón Montecarlo. Su construcción superior ofrece una experiencia de sueño elevated que transformará cómo wake up cada mañana. El soporte avanzado y la sensación premium hacen cada noche sentirse como una estancia en un resort cinco estrellas. Invierte en tu descanso y siente la diferencia.', '1.40 x 1.90 / 1.60 x 1.90 / 2.00 x 2.00', 'Standard', 1, 'colchones'),
  (41, 'COLCHON ATENAS', 2120000, 'https://res.cloudinary.com/dj5dehk8y/image/upload/v1776887521/COLCHON_ATENAS_hczp2l.jpg', 'El.colchón Atenas es la cima de la excelencia en descanso. Su construcción premium класса mondiale ofrece el máximo nivel de soporte y comfort disponible. Cada capa está diseñada para proporcionar la experiencia de sueño más refinada posible, para quienes mereces nothing but the best. Despierta verdaderamente descansado cada día.', '1.40 x 1.90 / 1.60 x 1.90 / 2.00 x 2.00', 'Standard', 1, 'colchones'),
